class Program
{
    static void Main()
    {
        var maxHeap = new PriorityQueue<int, int>();
        int[] nums = { 3, 1, 4, 1, 5, 9, 2, 6 };
        foreach (int n in nums)
            maxHeap.Enqueue(n, -n);

        Console.Write("Top 3: ");
        for (int i = 0; i < 3; i++)
            Console.Write(maxHeap.Dequeue() + " ");
        Console.WriteLine();  // Top 3: 9 6 5
    }
}

