class Program
{
    static void Main()
    {
        var set = new SortedSet<int> { 5, 3, 8, 1, 9 };
        Console.WriteLine(set.Min);   // 1
        Console.WriteLine(set.Max);   // 9

        set.Remove(set.Min);
        Console.WriteLine(set.Min);   // 3

        var tupleSet = new SortedSet<(int val, int idx)>();
        tupleSet.Add((5, 0));
        tupleSet.Add((5, 1));
        Console.WriteLine(tupleSet.Count);  // 2 (duplicates via index)
    }
}

