class Program
{
    static int[] TopK(int[] nums, int k)
    {
        var pq = new PriorityQueue<int, int>();
        foreach (int n in nums)
        {
            pq.Enqueue(n, n);
            if (pq.Count > k)
                pq.Dequeue();
        }
        int[] result = new int[k];
        for (int i = k - 1; i >= 0; i--)
            result[i] = pq.Dequeue();
        return result;
    }

    static void Main()
    {
        int[] nums = { 3, 7, 1, 9, 4, 6, 2, 8, 5 };
        int[] top3 = TopK(nums, 3);
        Console.WriteLine(String.Join(", ", top3));  // 7, 8, 9
    }
}

